    const L = parseFloat(length);
    const W = parseFloat(width);
    const H = parseFloat(height);
    const D = parseInt(doors);
    const Win = parseInt(windows);
    const C = parseInt(coats);
    const Cov = parseFloat(coverage);
    const Can = parseFloat(canSize);

    if (!L || !W || !H || L <= 0 || W <= 0 || H <= 0) {
      toast.error('يرجى إدخال أبعاد الغرفة');
      return;
    }

    const wallArea = 2 * (L + W) * H;
    const deductions = D * 2.0 + Win * 1.5; // average door 2m², window 1.5m²
    const netArea = Math.max(wallArea - deductions, 0);
    const totalArea = netArea * C;
    const litersNeeded = parseFloat((totalArea / Cov).toFixed(2));
    const cansNeeded = Math.ceil(litersNeeded / Can);
    const primeCoatLiters = parseFloat((netArea / (Cov * 1.2)).toFixed(2));

    setResult({ netArea: parseFloat(netArea.toFixed(2)), totalArea: parseFloat(totalArea.toFixed(2)), litersNeeded, cansNeeded, primeCoatLiters });
    toast.success('تم حساب كميات الدهان');
