import React, { useState, useCallback } from 'react';
import { toast } from 'sonner';

interface AsphaltLayer {
  id: string;
  name: string;
  thickness: number;
  density: number;
}

interface AsphaltResult {
  layers: { name: string; volume: number; weight: number }[];
  totalVolume: number;
  totalWeight: number;
  totalArea: number;
}

const defaultLayers: AsphaltLayer[] = [
  { id: 'layer-base', name: 'طبقة الأساس (Base Course)', thickness: 10, density: 2.3 },
  { id: 'layer-binder', name: 'طبقة الرابط (Binder Course)', thickness: 7, density: 2.35 },
  { id: 'layer-wearing', name: 'طبقة الرداء (Wearing Course)', thickness: 4, density: 2.4 },
];

