'use client';
import React, { useState, useCallback } from 'react';
import { toast } from 'sonner';

interface ConcreteResult {
  volume: number;
  cement: number;
  sand: number;
  gravel: number;
  water: number;
  bags: number;
}

const mixRatios: Record<string, { c: number; s: number; g: number; w: number; label: string }> = {
  'B150': { c: 1, s: 3, g: 6, w: 0.6, label: 'B150 — عادي' },
  'B200': { c: 1, s: 2.5, g: 5, w: 0.55, label: 'B200 — متوسط' },
  'B250': { c: 1, s: 2, g: 4, w: 0.5, label: 'B250 — جيد' },
  'B300': { c: 1, s: 1.5, g: 3, w: 0.45, label: 'B300 — عالي' },
  'B350': { c: 1, s: 1.2, g: 2.5, w: 0.42, label: 'B350 — عالي جداً' },
};

