  const [shape, setShape] = useState<'slab' | 'column' | 'beam' | 'footing'>('slab');
  const [dim1, setDim1] = useState('');
  const [dim2, setDim2] = useState('');
  const [dim3, setDim3] = useState('');
  const [mixGrade, setMixGrade] = useState('B250');
  const [wasteFactor, setWasteFactor] = useState('1.05');
  const [result, setResult] = useState<ConcreteResult | null>(null);

  const shapeLabels: Record<typeof shape, { d1: string; d2: string; d3: string; icon: string }> = {
    slab: { d1: 'الطول (م)', d2: 'العرض (م)', d3: 'السُمك (م)', icon: '▬' },
    column: { d1: 'العرض (م)', d2: 'العمق (م)', d3: 'الارتفاع (م)', icon: '▮' },
    beam: { d1: 'الطول (م)', d2: 'العرض (م)', d3: 'الارتفاع (م)', icon: '━' },
    footing: { d1: 'الطول (م)', d2: 'العرض (م)', d3: 'السُمك (م)', icon: '◼' },
  };

  const calculate = useCallback(() => {
    const d1 = parseFloat(dim1);
    const d2 = parseFloat(dim2);
    const d3 = parseFloat(dim3);
    const WF = parseFloat(wasteFactor);

    if (isNaN(d1) || isNaN(d2) || isNaN(d3) || d1 <= 0 || d2 <= 0 || d3 <= 0) {
      toast.error('يرجى إدخال جميع الأبعاد');
      return;
    }

    const rawVolume = d1 * d2 * d3;
    const volume = parseFloat((rawVolume * WF).toFixed(3));

    const mix = mixRatios[mixGrade];
    const totalParts = mix.c + mix.s + mix.g;
    const cementVolume = (mix.c / totalParts) * volume;
    const cementDensity = 1500; // kg/m³
    const cement = parseFloat((cementVolume * cementDensity).toFixed(1));
    const sand = parseFloat(((mix.s / totalParts) * volume * 1600).toFixed(1));
    const gravel = parseFloat(((mix.g / totalParts) * volume * 1700).toFixed(1));
    const water = parseFloat((cement * mix.w).toFixed(1));
    const bags = Math.ceil(cement / 50);

    setResult({ volume, cement, sand, gravel, water, bags });
    toast.success('تم حساب كميات الخرسانة');
  }, [dim1, dim2, dim3, mixGrade, wasteFactor]);

