'use client';
import React, { useState, useCallback } from 'react';
import { toast } from 'sonner';

interface AADTResult {
  designHourlyVolume: number;
  lanesRequired: number;
  capacityPerLane: number;
  vcRatio: number;
  los: string;
  losColor: string;
}

const LOS_TABLE = [
  { max: 0.35, level: 'A — تدفق حر ممتاز', color: '#10b981' },
  { max: 0.54, level: 'B — تدفق جيد', color: '#34d399' },
  { max: 0.77, level: 'C — تدفق مستقر', color: '#f59e0b' },
  { max: 0.90, level: 'D — تدفق متقارب من الاكتظاظ', color: '#f97316' },
  { max: 1.00, level: 'E — تدفق عند الطاقة القصوى', color: '#ef4444' },
  { max: Infinity, level: 'F — تدفق منهار (ازدحام)', color: '#991b1b' },
];

