  const [kFactor, setKFactor] = useState('0.09');
  const [dFactor, setDFactor] = useState('0.55');
  const [phf, setPhf] = useState('0.92');
  const [roadType, setRoadType] = useState<'highway' | 'arterial' | 'collector'>('highway');
  const [result, setResult] = useState<AADTResult | null>(null);

  const capacityMap = { highway: 2200, arterial: 1800, collector: 1400 };

  const calculate = useCallback(() => {
    const AADT = parseFloat(aadt);
    const K = parseFloat(kFactor);
    const D = parseFloat(dFactor);
    const PHF = parseFloat(phf);

    if (!AADT || AADT <= 0) {
      toast.error('يرجى إدخال AADT صحيح');
      return;
    }

    const DHV = AADT * K;
    const DDHV = DHV * D;
    const capacityPerLane = capacityMap[roadType];
    const lanesFloat = DDHV / (capacityPerLane * PHF);
    const lanesRequired = Math.ceil(lanesFloat);
    const vcRatio = DDHV / (lanesRequired * capacityPerLane * PHF);

    const losEntry = LOS_TABLE.find((e) => vcRatio <= e.max) ?? LOS_TABLE[LOS_TABLE.length - 1];

    setResult({
      designHourlyVolume: Math.round(DDHV),
      lanesRequired,
      capacityPerLane,
      vcRatio: parseFloat(vcRatio.toFixed(3)),
      los: losEntry.level,
      losColor: losEntry.color,
    });
    toast.success('تم تحليل AADT');
  }, [aadt, kFactor, dFactor, phf, roadType]);

