  const [speed, setSpeed] = useState('');
  const [lanes, setLanes] = useState('2');
  const [laneWidth, setLaneWidth] = useState('3.65');
  const [result, setResult] = useState<SuperResult | null>(null);

  const calculate = useCallback(() => {
    const R = parseFloat(radius);
    const V = parseFloat(speed);
    const n = parseInt(lanes);
    const w = parseFloat(laneWidth);

    if (!R || !V || R <= 0 || V <= 0) {
      toast.error('يرجى إدخال قيم صحيحة للمتغيرات');
      return;
    }

    // AASHTO superelevation method
    // emax typically 8% for rural highways
    const emax = 0.08;
    // Design superelevation: e = V² / (127 * R) - f_s  (simplified)
    // Side friction factor fs based on speed
    const fs = V <= 50 ? 0.18 : V <= 80 ? 0.14 : V <= 110 ? 0.11 : 0.09;
    const eCalc = (V * V) / (127 * R) - fs;
    const eDesign = Math.min(Math.max(eCalc, -0.02), emax);

    // Transition length based on AASHTO: L = (w * n * Δe) / (relative gradient)
    const relGrad = V <= 60 ? 0.005 : V <= 80 ? 0.004 : 0.0035;
    const deltaE = Math.abs(eDesign - (-0.02)); // from normal crown
    const transLength = Math.round((w * n * deltaE) / relGrad);
    const runoffLength = Math.round(transLength * 0.67);
    const tangentRunout = transLength - runoffLength;

    setResult({
      emax: emax * 100,
      eDesign: parseFloat((eDesign * 100).toFixed(2)),
      transitionLength: transLength,
      runoffLength: runoffLength,
      tangentRunout: tangentRunout,
    });
    toast.success('تم الحساب بنجاح');
  }, [radius, speed, lanes, laneWidth]);

