        {activeTab === 'conversions' && <ConversionsSection data-component-id="src/app/main-engineering-platform/components/PlatformTabs.tsx:110:40" data-component-path="src/app/main-engineering-platform/components/PlatformTabs.tsx" data-component-line="110" data-component-end-line="110" data-component-file="PlatformTabs.tsx" data-component-name="ConversionsSection" data-component-content="%7B%22elementName%22%3A%22ConversionsSection%22%7D" />}
