'use client';
import React, { useState, useCallback } from 'react';
import { toast } from 'sonner';

interface RebarItem {
  id: string;
  diameter: number;
  length: number;
  count: number;
}

interface RebarResult {
  totalLength: number;
  totalWeight: number;
  byDiameter: { dia: number; length: number; weight: number }[];
}

const REBAR_WEIGHTS: Record<number, number> = {
  8: 0.395, 10: 0.617, 12: 0.888, 14: 1.21, 16: 1.58,
  18: 2.0, 20: 2.47, 22: 2.98, 25: 3.85, 28: 4.83, 32: 6.31,
};

