  const [items, setItems] = useState<RebarItem[]>([
    { id: 'rebar-001', diameter: 12, length: 6, count: 20 },
    { id: 'rebar-002', diameter: 16, length: 8, count: 15 },
  ]);
  const [result, setResult] = useState<RebarResult | null>(null);

  const addItem = () => {
    const newId = `rebar-${String(items.length + 1).padStart(3, '0')}`;
    setItems((prev) => [...prev, { id: newId, diameter: 12, length: 6, count: 1 }]);
  };

  const removeItem = (id: string) => {
    setItems((prev) => prev.filter((i) => i.id !== id));
  };

  const updateItem = (id: string, field: keyof Omit<RebarItem, 'id'>, value: number) => {
    setItems((prev) => prev.map((i) => (i.id === id ? { ...i, [field]: value } : i)));
  };

  const calculate = useCallback(() => {
    if (items.length === 0) { toast.error('أضف صنفاً واحداً على الأقل'); return; }

    const byDiaMap: Record<number, number> = {};
    items.forEach((item) => {
      const total = item.length * item.count;
      byDiaMap[item.diameter] = (byDiaMap[item.diameter] || 0) + total;
    });

    const byDiameter = Object.entries(byDiaMap).map(([dia, len]) => {
      const d = parseInt(dia);
      const wPerM = REBAR_WEIGHTS[d] ?? (d * d * 0.00617);
      return { dia: d, length: parseFloat(len.toFixed(2)), weight: parseFloat((len * wPerM).toFixed(2)) };
    });

    const totalLength = byDiameter.reduce((s, b) => s + b.length, 0);
    const totalWeight = byDiameter.reduce((s, b) => s + b.weight, 0);

    setResult({
      totalLength: parseFloat(totalLength.toFixed(2)),
      totalWeight: parseFloat(totalWeight.toFixed(2)),
      byDiameter,
    });
    toast.success('تم حساب كميات الحديد');
  }, [items]);

