  const [fillSlope, setFillSlope] = useState('2');
  const [fillHeight, setFillHeight] = useState('3');
  const [result, setResult] = useState<CSResult | null>(null);

  const calculate = useCallback(() => {
    const n = parseInt(numLanes);
    const lw = parseFloat(laneW);
    const sw = parseFloat(shoulderW);
    const mw = isSplit ? parseFloat(medianW) : 0;
    const fs = parseFloat(fillSlope);
    const fh = parseFloat(fillHeight);

    if (!n || !lw || !sw || n <= 0 || lw <= 0) {
      toast.error('يرجى إدخال قيم صحيحة');
      return;
    }

    const pavementWidth = n * lw;
    const totalWidth = pavementWidth + 2 * sw + (isSplit ? mw : 0);
    const slopeArea = 2 * (fh * (fs * fh + totalWidth / 2));
    const totalROW = totalWidth + 2 * (fs * fh) + 2 * 5; // 5m extra for ROW

    setResult({
      totalWidth: parseFloat(totalWidth.toFixed(2)),
      pavementWidth: parseFloat(pavementWidth.toFixed(2)),
      shoulderWidth: parseFloat((2 * sw).toFixed(2)),
      medianWidth: isSplit ? parseFloat(mw.toFixed(2)) : null,
      slopeArea: parseFloat(slopeArea.toFixed(2)),
      totalROW: parseFloat(totalROW.toFixed(2)),
    });
    toast.success('تم حساب المقطع العرضي');
  }, [numLanes, laneW, shoulderW, medianW, isSplit, fillSlope, fillHeight]);

